namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelper
    {
        /// <summary>
        /// Creates a SchoolContext backed by the InMemory provider with a unique database name.
        /// </summary>
        public static SchoolContext CreateContext(string dbName)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        /// <summary>
        /// Drains the static NotificationService queue to prevent cross-test interference.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            using var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }
    }
}

