using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _service = new NotificationService();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _service?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        // ── SendNotification (4-param overload, no display name) ──

        [TestMethod]
        public void SendNotification_WithoutDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
        }

        // ── ReceiveNotification ──

        [TestMethod]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            var result = _service.ReceiveNotification();
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleItems_DequeuesInFifoOrder()
        {
            _service.SendNotification("Course", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Course", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.AreEqual("1", first.EntityId);
            Assert.AreEqual("2", second.EntityId);
            Assert.AreEqual("3", third.EntityId);
        }

        // ── Default/custom userName ──

        [TestMethod]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_CustomUserName_IsSet()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "AdminUser");

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("AdminUser", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_FiveParamOverload_CustomUserName_IsSet()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "AdminUser");

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("AdminUser", notification.CreatedBy);
        }

        // ── GenerateMessage (tested via public API) ──

        [TestMethod]
        public void GenerateMessage_Create_WithDisplayName_ContainsCreated()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        }

        [TestMethod]
        public void GenerateMessage_Update_WithDisplayName_ContainsUpdated()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void GenerateMessage_Delete_WithDisplayName_ContainsDeleted()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void GenerateMessage_Create_WithoutDisplayName_UsesId()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void GenerateMessage_Update_WithoutDisplayName_UsesId()
        {
            _service.SendNotification("Course", "100", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Course (ID: 100) has been updated", notification.Message);
        }

        [TestMethod]
        public void GenerateMessage_Delete_WithoutDisplayName_UsesId()
        {
            _service.SendNotification("Department", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Department (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void GenerateMessage_WithEmptyDisplayName_UsesId()
        {
            _service.SendNotification("Student", "7", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        [TestMethod]
        public void GenerateMessage_WithWhitespaceDisplayName_UsesId()
        {
            _service.SendNotification("Student", "7", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        // ── Notification properties ──

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now.AddSeconds(-1);

            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            var after = DateTime.Now.AddSeconds(1);

            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
                $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.IsFalse(notification.IsRead);
        }

        // ── MarkAsRead ──

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            _service.MarkAsRead(1);
            _service.MarkAsRead(0);
            _service.MarkAsRead(-1);
            // No-op for in-memory implementation — just verify no exception
        }

        // ── Dispose ──

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            _service.Dispose();
            // No-op — just verify no exception
        }

        [TestMethod]
        public void Dispose_CalledMultipleTimes_DoesNotThrow()
        {
            _service.Dispose();
            _service.Dispose();
        }

        // ── Queue cap enforcement ──

        [TestMethod]
        public void SendNotification_ExceedingMaxQueueLength_EvictsOldest()
        {
            // Enqueue 505 items; queue cap is 500
            for (int i = 0; i < 505; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Dequeue all and count
            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            Assert.IsTrue(count <= 500, $"Queue should enforce max length of 500, got {count}");
        }

        // ── All EntityOperation values ──

        [TestMethod]
        [DataRow(EntityOperation.CREATE)]
        [DataRow(EntityOperation.UPDATE)]
        [DataRow(EntityOperation.DELETE)]
        public void SendNotification_AllOperations_SetsOperationString(EntityOperation operation)
        {
            _service.SendNotification("Entity", "1", operation);

            var notification = _service.ReceiveNotification();

            Assert.AreEqual(operation.ToString(), notification.Operation);
        }
    }
}

using ContosoUniversity.Tests.Helpers;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<string> { "a", "b" };

            var list = new PaginatedList<string>(items, 10, 3, 5);

            Assert.AreEqual(3, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_CalculatesTotalPages()
        {
            // 10 items / page size 3 = ceil(3.33) = 4 pages
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 1, 3);

            Assert.AreEqual(4, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_TotalPages_ExactDivision()
        {
            // 10 items / page size 5 = 2 pages
            var items = new List<string> { "a", "b", "c", "d", "e" };

            var list = new PaginatedList<string>(items, 10, 1, 5);

            Assert.AreEqual(2, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItems()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 1, 5);

            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("a", list[0]);
            Assert.AreEqual("b", list[1]);
            Assert.AreEqual("c", list[2]);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);

            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);

