using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext($"NotifTest_{Guid.NewGuid()}");
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsEmptyNotifications()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            // Result is JsonResult with anonymous type
            var json = result.Value;
            Assert.IsNotNull(json);
        }

        [TestMethod]
        public void GetNotifications_WithItems_ReturnsNotifications()
        {
            // Enqueue some notifications
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "John", EntityOperation.CREATE);
            svc.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);
            svc.Dispose();

            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10()
        {
            // Enqueue 15 notifications
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }
            svc.Dispose();

            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            // After getting notifications, there should be 5 remaining in the queue
            var svc2 = new NotificationService();
            int remaining = 0;
            while (svc2.ReceiveNotification() != null) remaining++;
            Assert.AreEqual(5, remaining);
            svc2.Dispose();
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
        }
    }
}

