using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private SchoolContext _context;
        private CoursesController _controller;
        private Mock<IWebHostEnvironment> _envMock;
        private Mock<ILogger<CoursesController>> _loggerMock;
        private string _tempDir;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext($"CoursesTest_{Guid.NewGuid()}");

            _tempDir = Path.Combine(Path.GetTempPath(), $"CoursesTest_{Guid.NewGuid()}");
            Directory.CreateDirectory(_tempDir);

            _envMock = new Mock<IWebHostEnvironment>();
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _loggerMock = new Mock<ILogger<CoursesController>>();

            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelper.DrainNotificationQueue();

            // Clean up temp directory
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        private void SeedCoursesWithDepartment()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            _context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = dept.DepartmentID }
            );
            _context.SaveChanges();
        }

        private Mock<IFormFile> CreateMockFile(string fileName, long length)
        {
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return fileMock;
        }

        // ── Index ──

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
            SeedCoursesWithDepartment();

            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void Index_EmptyDb_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        // ── Details ──

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            Assert.IsInstanceOfType(result, typeof(StatusCodeResult));
            Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsCourse()
        {
            SeedCoursesWithDepartment();

            var result = _controller.Details(1050) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
            Assert.AreEqual(1050, model.CourseID);
            Assert.AreEqual("Chemistry", model.Title);
        }

        // ── Create GET ──

        [TestMethod]
        public void Create_Get_ReturnsView()
        {
            SeedCoursesWithDepartment();

            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
        }

        // ── Create POST ──

        [TestMethod]
        public void Create_Post_Valid_NoImage_SavesAndRedirects()
        {
            SeedCoursesWithDepartment();
            var dept = _context.Departments.First();

            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(4, _context.Courses.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidExtension_AddsModelError()
        {
            SeedCoursesWithDepartment();
            var dept = _context.Departments.First();

            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFile("test.exe", 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        [DataRow(".jpg")]
        [DataRow(".jpeg")]
        [DataRow(".png")]
        [DataRow(".gif")]
        [DataRow(".bmp")]
        public void Create_Post_ValidExtensions_Accepted(string extension)
        {
            SeedCoursesWithDepartment();
            var dept = _context.Departments.First();

            var course = new Course
            {
                CourseID = 9900 + new Random().Next(1, 99),
                Title = "Course With Image",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = CreateMockFile($"test{extension}", 1024);

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Create_Post_TooLargeFile_AddsModelError()
        {
