        private void SeedInstructorsWithCoursesAndDepartments()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID,
                    Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID,
                    Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = dept.DepartmentID,
                    Enrollments = new List<Enrollment>(), CourseAssignments = new List<CourseAssignment>() }
            };
            _context.Courses.AddRange(courses);
            _context.SaveChanges();

            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>()
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.AddRange(instructor1, instructor2);
            _context.SaveChanges();

            // Add course assignments
            _context.CourseAssignments.AddRange(
                new CourseAssignment { CourseID = 1050, InstructorID = instructor1.ID },
                new CourseAssignment { CourseID = 1045, InstructorID = instructor2.ID }
            );
            _context.SaveChanges();

            // Add office assignment
            _context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor2.ID,
                Location = "Smith 17"
            });
            _context.SaveChanges();

            // Update department admin
            dept.InstructorID = instructor1.ID;
            _context.SaveChanges();
        }

